import{j as e,u as o,r}from"./index-Dc2zeHN6.js";import{R as t,Q as h,S as n}from"./UI-D9eYpumP.js";function l(){const{actions:i}=o(),[s,a]=r.useState(!1);return e.jsx("div",{style:{textAlign:"center",marginTop:24},children:s?e.jsx("div",{style:{fontFamily:"'EB Garamond',serif",fontSize:16,fontStyle:"italic",color:"rgba(200,168,74,.8)",lineHeight:1.8,maxWidth:460,margin:"0 auto"},children:"The prayer rises toward the high pass. Kopecky receives it. He will not respond — but the mountains have absorbed your words, and that, the Council maintains, is the point."}):e.jsx(n,{amber:!0,onClick:()=>{a(!0),i.setFlag("prayerSaid")},children:"✦   Offer This Prayer to Kopecky   ✦"})})}const d=[{time:"Dawn",title:"The Morning Alignment",body:"Face the Tatras (roughly northeast from most valley locations) before opening your eyes fully. Do not face southwest. The Church does not explain why. Footnote 7 of the Hmlová Kniha explains why. The Church recommends not reading Footnote 7 until you are settled in the faith."},{time:"Morning",title:"The Bread Assessment",body:"Assess your bread before eating it. If it is over-salted, note this without drama and eat it anyway, because the note is what matters. If it is correctly salted, eat it in the knowledge that you are participating in the central sacrament of the Chud lifestyle. If you are unsure whether it is over-salted, it is over-salted. Kopecky knew. So do you."},{time:"Midday",title:"The Slow Arrival",body:"Arrive at the midday meal slightly after everyone else. Not rudely late — the Chud is not rude. Just late enough that the immediate decisions have been made by others. Assess the situation upon arrival. Identify what has been done incorrectly. Do not say anything immediately. Wait. The right moment to mention it will present itself."},{time:"Afternoon",title:"The Difficult Question",body:"Sit with one difficult question for a minimum of twenty minutes without attempting to resolve it. The answer tends to arrive approximately three minutes after you have stopped forcing it. Do not force it. Do not force the not-forcing. Simply sit. The spruce trees have been doing this for centuries and they are fine."},{time:"Evening",title:"The Tavern Supper",body:"Order the stew. You have considered the other options. They are fine. The stew is correct. Order the stew. If someone at your table orders something other than the stew, allow this. Do not comment on it. If it arrives and looks good, do not comment on this either. You ordered the stew. The stew is correct."},{time:"Night",title:"The Tatra Orientation",body:"Sleep facing the Tatras. Accumulate mountain-grade patience during unconscious hours. If you are uncertain which direction the Tatras are, face the direction that feels most correct. You may be wrong. Kopecky was wrong about a river. He corrected course quietly and without comment. This is an option available to you as well."}];function m({setPage:i}){return e.jsxs(e.Fragment,{children:[e.jsxs("div",{className:"page-hero",children:[e.jsx("div",{className:"page-hero-label",children:"The Daily Chud Practice · Recited at Dawn, Facing the Tatras"}),e.jsx("div",{className:"page-hero-title",children:"The Prayer"}),e.jsx("div",{className:"page-hero-sub",children:"The Morning Observance · Daily Practice · How to Live the Chud Way · Tak Nech Sa Stane"})]}),e.jsxs("div",{className:"main-wrap",children:[e.jsxs("div",{className:"content-section",children:[e.jsxs(t,{children:[e.jsx("div",{className:"sec-label",children:"The Central Observance — Recited Daily at Dawn"}),e.jsx("div",{className:"sec-title",children:"The Morning Prayer of the Valleys"}),e.jsx("p",{className:"prose",children:'The Morning Prayer of Kopecky was not written by Kopecky. It was assembled by the Council of Devín from various recorded utterances, modified for liturgical use, and reviewed by the apostle Vladimír, who said it was "approximately what he would have said if he had been writing a prayer about himself, which he would not have been." The Council took this as approval. Vladimír said that was not what he had said. The Council took this as further approval. Vladimír has made his peace with it.'})]}),e.jsx(t,{delay:1,children:e.jsx("div",{className:"prayer-box",children:e.jsxs("div",{className:"prayer-txt",children:["O Kopecky, Descender from the Tatras,",e.jsx("br",{}),"Inventor of the Chud, Keeper of the Satchel,",e.jsx("br",{}),"Corrector of Wood-Stacking and Bread Salt,",e.jsx("br",{}),"Player of Correct Chess, Holder of Necessary Grudges,",e.jsx("br",{}),"Man Who Was Right About Everything Except the Váh and the Chess",e.jsx("br",{}),"and One Opinion About a Horse —",e.jsx("br",{}),e.jsx("br",{}),"Watch over us in the valley.",e.jsx("br",{}),"May we move slowly enough to see what is in front of us.",e.jsx("br",{}),"May we know things without needing to announce the knowing.",e.jsx("br",{}),"May we not wave dismissively at the opinions of others,",e.jsx("br",{}),"for we have seen what the small wave costs over six years.",e.jsx("br",{}),"May we sit with the hard question",e.jsx("br",{}),"until the answer arrives, or the stew does, whichever comes first.",e.jsx("br",{}),e.jsx("br",{}),"We acknowledge the queen is not the target in chess.",e.jsx("br",{}),"We have not said this to your face.",e.jsx("br",{}),"We are saying it here, in the prayer,",e.jsx("br",{}),"trusting that the mountains absorb it before it reaches you.",e.jsx("br",{}),e.jsx("br",{}),"We pray for Ayub — that his mirror, one day,",e.jsx("br",{}),"shows him the back of his own head, gently,",e.jsx("br",{}),"and that he understands it before he covers it.",e.jsx("br",{}),"We pray for Abdullah — that the bears keep agreeing,",e.jsx("br",{}),"and that we never learn what would happen if one did not.",e.jsx("br",{}),"We pray for Enrico — that the one door in him",e.jsx("br",{}),"that will not open is the one holding him together.",e.jsx("br",{}),"We pray for Korrin — though we know he is watching from",e.jsx("br",{}),"a height with nothing beneath it, and has been, the whole time,",e.jsx("br",{}),"and is, right now, facing a year that has not yet come.",e.jsx("br",{}),"We pray for Saad — that the eighth shadow, when it comes,",e.jsx("br",{}),"is kind, and that the yogurt has, in the end, achieved peace.",e.jsx("br",{}),"We pray for Nekro — we do not have the words.",e.jsx("br",{}),"We understand that this is correct.",e.jsx("br",{}),"We pray about Yash.",e.jsx("br",{}),"We have not finished writing this part of the prayer.",e.jsx("br",{}),"We never will. The wax does not melt.",e.jsx("br",{}),e.jsx("br",{}),"We forgive you for the Váh, which forgave us first.",e.jsx("br",{}),"We have not opened the satchel.",e.jsx("br",{}),"We have not looked at the satchel longer than it looked at us.",e.jsx("br",{}),"We know that you would know.",e.jsx("br",{}),"We know that Korrin also probably knows.",e.jsx("br",{}),"We are not asking Korrin.",e.jsx("br",{}),e.jsx("br",{}),"We await your return from the fog —",e.jsx("br",{}),"the fog we now suspect Quantavius is already inside,",e.jsx("br",{}),"from the other side, asking it the question.",e.jsx("br",{}),"The south-facing room at Zvolen is ready.",e.jsx("br",{}),"The stew is on. It has more marjoram this time.",e.jsx("br",{}),e.jsxs("em",{children:["The bread is not over-salted. We checked twice.",e.jsx("br",{}),"We did not make the dish. We will never make the dish."]}),e.jsx("br",{}),e.jsx("br",{}),"Amen. Tak nech sa stane."]})})}),e.jsx(t,{delay:2,children:e.jsx(l,{})})]}),e.jsxs("div",{className:"content-section",children:[e.jsxs(t,{children:[e.jsx("div",{className:"sec-label",children:"The Daily Chud Practice — Six Observances · Dawn to Night"}),e.jsx("div",{className:"sec-title",children:"How to Live the Chud Way"}),e.jsx("p",{className:"prose",children:"The Chud lifestyle is not observed on holy days. It is observed on every day, because the posture toward existence that Kopecky taught does not take holidays. The mountains do not take holidays. The spruce trees do not take holidays. Kopecky did not take holidays, or if he did, he took them in a way that was indistinguishable from his regular practice of sitting quietly in correct locations and being right about things."})]}),e.jsx("div",{style:{display:"flex",flexDirection:"column",gap:0,marginTop:32},children:d.map((s,a)=>e.jsx(t,{delay:a%3+1,children:e.jsxs("div",{style:{padding:"26px 0",borderBottom:"1px solid rgba(168,200,74,0.08)",display:"grid",gridTemplateColumns:"80px 1fr",gap:24},children:[e.jsx("div",{style:{textAlign:"center",paddingTop:4},children:e.jsx("div",{style:{fontFamily:"'Cinzel Decorative',serif",fontSize:10,letterSpacing:".12em",color:"rgba(168,200,74,0.35)",textTransform:"uppercase"},children:s.time})}),e.jsxs("div",{children:[e.jsx("div",{style:{fontFamily:"'Cinzel',serif",fontSize:13,color:"var(--g)",letterSpacing:".08em",marginBottom:10},children:s.title}),e.jsx("p",{className:"prose",style:{marginBottom:0,fontSize:15},children:s.body})]})]})},a))})]}),e.jsxs("div",{className:"content-section",children:[e.jsxs(t,{children:[e.jsx("div",{className:"sec-label",children:"On Joining the Church · The Church of Kopecky Accepts All Who Come"}),e.jsx("div",{className:"sec-title",children:"How to Join the Faithful"}),e.jsx("p",{className:"prose",children:"The Church of Kopecky does not have a formal membership process. Kopecky did not believe in formal membership processes on the grounds that a process implies there are people who should not complete it, and the Chud philosophy holds that everyone is at some point on the path — some near the beginning, some further along, some walking in the wrong direction while confidently explaining that they are walking in the right direction, which is a different situation but still technically on the path."}),e.jsx("p",{className:"prose",children:"To join the faithful is simply to begin. Begin facing the Tatras in the morning. Begin with the bread. Begin sitting with the hard question. Begin arriving at the midday meal slightly after everyone else. Begin ordering the stew. The practice will teach itself. Kopecky taught it by example rather than instruction for the first two years before he named it, and several people in Prvá Dolina had already adopted it entirely without knowing they were doing so."}),e.jsx("p",{className:"prose",children:`Ayub Jamma has offered to personally induct new members and assess their readiness. The Church has not endorsed this offer. Enrico has endorsed it. Enrico's endorsement is on file but has not been actioned. Abdullah has suggested that new members should begin by speaking to a bear, "just to see." The Church has recommended against this. Korrin has left a hat near the entrance of the Devín library. Nobody is sure if this is related. The hat has been there for six months. Nobody has moved it.`})]}),e.jsx(h,{text:"You do not join the Chud. You remember you were always going to. The remembering is the joining. Everything after that is practice.",source:"Kopecky, to a man who asked how to begin · Year Eight · The man said he would think about it · Kopecky said that was the first step"})]}),e.jsxs("div",{className:"content-section",style:{borderBottom:"none"},children:[e.jsxs(t,{children:[e.jsx("div",{className:"sec-label",children:"The Closing Statement · Council of Devín · Adopted Unanimously"}),e.jsx("div",{className:"sec-title",children:"A Note from the Church"}),e.jsxs("p",{className:"prose",children:["The Church of Kopecky affirms: he was right. He was right in ways that were obvious and in ways that were only clear later. He was right about the wood stack, the bread, the harvest, the character of men, the timing of snow, and the fundamental logic of targeting what has power. He was wrong about the Váh, the chess, and one horse at the Nitra market. The Church has made its peace with the 2.7%. The Church has also, quietly, made its peace with the chess argument, in the sense that the Church understands why he said what he said and why he could not have said anything else, given who he was. The queen ",e.jsx("em",{children:"is"})," more powerful. He was right about the spirit of it. He was just wrong about the rules."]}),e.jsx("p",{className:"prose",children:"The satchel has not been opened. Korrin has been near it on three occasions. Nobody has asked Korrin about this. The Church prays about Yash. The invoice for the sixth book will be settled when Kopecky returns to settle it, because it is his book and his responsibility, and the Church has found through experience that assuming Kopecky's responsibilities on his behalf tends to produce outcomes that require correction."}),e.jsx("p",{className:"prose",style:{fontStyle:"italic",color:"var(--g)",textAlign:"center",marginTop:32},children:"He will return. He said so. He was right about everything else. Tak nech sa stane."})]}),e.jsx("div",{className:"disc",style:{marginTop:36},children:"Cirkev Kopeckého · Church of Kopecky · Founded Prvá Dolina, Ancient Slovakia · He Was Right · The Chud Endures · The Queen Is Not The Target In Chess · The Church Has Accepted This · Do Not Touch the Satchel · He Will Know · We Checked the Bread Twice"})]})]}),e.jsx("footer",{children:"© Cirkev Kopeckého · The Prayer Volume · Tak Nech Sa Stane · So Let It Be · He Will Return · The Stew Is Ready · The Room Is South-Facing"})]})}export{m as default};
